109	pub fn ensure_accessible_page(session: &SessionContext, requested: Page) -> Page {
110	    if can_access(session, requested) {
111	        return requested;
112	    }
113	    if can_access(session, Page::Dashboard) {
114	        return Page::Dashboard;
115	    }
116	    const ALL_PAGES: [Page; 11] = [
117	        Page::Dashboard,
118	        Page::Patients,
119	        Page::Bedboard,
120	        Page::Dining,
121	        Page::Orders,
122	        Page::Campaigns,
123	        Page::Ingestion,
124	        Page::Admin,
125	        Page::Experiments,
126	        Page::Analytics,
127	        Page::Audits,
128	    ];
129	    for page in ALL_PAGES {
130	        if can_access(session, page) {
131	            return page;
132	        }
133	    }
134	    Page::Dashboard
135	}
