30	pub fn validate_attachment(file_name: &str, mime_type: &str, size_bytes: usize) -> Result<(), String> {
31	    let lower = file_name.to_ascii_lowercase();
32	    let exact_match = (lower.ends_with(".pdf") && mime_type == "application/pdf")
33	        || ((lower.ends_with(".jpg") || lower.ends_with(".jpeg"))
34	            && mime_type == "image/jpeg")
35	        || (lower.ends_with(".png") && mime_type == "image/png");
36	    if !exact_match {
37	        return Err("Attachment must be PDF/JPG/PNG with matching MIME type".to_string());
38	    }
39	    if size_bytes > 25 * 1024 * 1024 {
40	        return Err("Attachment exceeds 25 MB limit".to_string());
41	    }
42	    Ok(())
43	}
44	
45	pub fn queue_dropped_attachment(
46	    queue: &mut Vec<QueuedAttachment>,
47	    file_name: &str,
48	    mime_type: &str,
49	    bytes: Vec<u8>,
50	) -> Result<(), String> {
51	    validate_attachment(file_name, mime_type, bytes.len())?;
52	    if !queue
53	        .iter()
54	        .any(|item| item.file_name == file_name && item.mime_type == mime_type && item.bytes.len() == bytes.len())
55	    {
56	        queue.push(QueuedAttachment {
57	            file_name: file_name.to_string(),
58	            mime_type: mime_type.to_string(),
59	            bytes,
60	        });
61	    }
62	    Ok(())
63	}
