1459	    fn decorate_revision_deltas(mut item: RevisionTimelineDto, reveal_sensitive: bool) -> RevisionTimelineDto {
1460	        let before_map = Self::parse_object(&item.diff_before);
1461	        let after_map = Self::parse_object(&item.diff_after);
1462	        let mut keys = before_map.keys().cloned().collect::<Vec<_>>();
1463	        keys.extend(after_map.keys().cloned());
1464	        keys.sort();
1465	        keys.dedup();
1466	
1467	        let mut deltas = Vec::new();
1468	        for key in keys {
1469	            let before = before_map
1470	                .get(&key)
