846	    pub async fn set_order_status(&self, user: &AuthUser, order_id: i64, req: OrderStatusRequest) -> Result<(), ApiError> {
847	        self.authorize(user, "order.write").await?;
848	        let status = req.status.trim();
849	        let valid = ["Created", "Billed", "Canceled", "Credited"];
850	        if !valid.contains(&status) {
851	            return Err(ApiError::bad_request("Invalid order status"));
852	        }
853	
854	        let current = self.repo.get_order(order_id).await?.ok_or(ApiError::NotFound)?;
855	        self.ensure_order_access(user, &current).await?;
856	
857	        let transition_ok = match (current.status.as_str(), status) {
858	            ("Created", "Billed") => true,
859	            ("Created", "Canceled") => true,
860	            ("Billed", "Credited") => true,
861	            (a, b) if a == b => true,
862	            _ => false,
863	        };
864	        if !transition_ok {
865	            return Err(ApiError::bad_request("Invalid order transition"));
866	        }
867	        if Self::status_requires_reason(status)
868	            && req.reason.as_deref().unwrap_or(" ").trim().is_empty()
869	        {
870	            return Err(ApiError::bad_request(
871	                "Reason is required when canceling or crediting an order",
872	            ));
873	        }
874	
875	        let expected = req.expected_version.unwrap_or(current.version);
876	        let changed = self
877	            .repo
878	            .set_order_status_if_version(order_id, expected, status, req.reason.as_deref())
879	            .await?;
880	        if !changed {
881	            return Err(ApiError::Conflict);
882	        }
883	
884	        self.repo
885	            .append_audit(
886	                "order.status",
887	                "dining_order",
888	                &order_id.to_string(),
889	                &format!("{{\"status\":{}}}", serde_json::to_string(status).map_err(|_| ApiError::Internal)?),
890	                user.user_id,
891	            )
892	            .await?;
893	        self.repo.close_inactive_campaigns().await?;
894	        Ok(())
895	    }
