347	    let forbidden = guard.forbidden;
348	    let available_nav = nav_items()
349	        .iter()
350	        .copied()
351	        .filter(|item| can_access(&ctx, item.page))
352	        .map(|item| ShellNavItem {
353	            page: item.page,
354	            label: item.label,
355	        })
356	        .collect::<Vec<_>>();
357	
358	    rsx! {
359	        AppShell {
360	            username: ctx.stored.username.clone(),
361	            role: ctx.stored.role.clone(),
362	            current_page: page(),
363	            nav_items: available_nav,
364	            status: status(),
365	            error: error(),
366	            on_select_page: move |next_page| {
367	                page.set(next_page);
368	                set_hash_page(next_page);
369	            },
370	            on_sign_out: move |_| {
371	                clear_session();
372	                session.set(None);
373	                set_hash_page(Page::Dashboard);
374	                page.set(Page::Dashboard);
375	                status.set(String::new());
376	                error.set(String::new());
377	                clear_workspace_data(
378	                    selected_patient_id,
379	                    patient_results,
380	                    patient_profile,
381	                    patient_revisions,
382	                    patient_attachments,
383	                    orders,
384	                    order_note_timeline,
385	                    order_split_timeline,
386	                    order_status_reason,
387	                    ingestion_tasks,
388	                    ingestion_versions,
389	                    ingestion_runs,
390	                    attachment_queue,
391	                    upload_state_kind,
392	                    upload_progress,
393	                );
394	            },

60	
61	fn set_hash_page(page: Page) {
62	    #[cfg(target_arch = "wasm32")]
63	    {
64	        if let Some(window) = web_sys::window() {
65	            let _ = window
66	                .location()
67	                .set_hash(state::page_to_hash(page).trim_start_matches('#'));
68	        }
69	    }
70	    #[cfg(not(target_arch = "wasm32"))]
71	    {
72	        let _ = page;
73	    }
74	}
