76	fn clear_workspace_data(
77	    mut selected_patient_id: Signal<Option<i64>>,
78	    mut patient_results: Signal<Vec<PatientSearchResultDto>>,
79	    mut patient_profile: Signal<Option<PatientProfileDto>>,
80	    mut patient_revisions: Signal<Vec<RevisionTimelineDto>>,
81	    mut patient_attachments: Signal<Vec<AttachmentMetadataDto>>,
