84	    mut order_split_timeline: Signal<Vec<TicketSplitDto>>,
85	    mut order_status_reason: Signal<String>,
86	    mut ingestion_tasks: Signal<Vec<IngestionTaskDto>>,
87	    mut ingestion_versions: Signal<Vec<IngestionTaskVersionDto>>,
88	    mut ingestion_runs: Signal<Vec<IngestionTaskRunDto>>,
89	    mut attachment_queue: Signal<Vec<QueuedAttachment>>,
90	    mut upload_state_kind: Signal<UploadState>,
91	    mut upload_progress: Signal<u8>,
92	) {
93	    selected_patient_id.set(None);
94	    patient_results.set(Vec::new());
95	    patient_profile.set(None);
96	    patient_revisions.set(Vec::new());
97	    patient_attachments.set(Vec::new());
98	    orders.set(Vec::new());
99	    order_note_timeline.set(Vec::new());
100	    order_split_timeline.set(Vec::new());
101	    order_status_reason.set(String::new());
102	    ingestion_tasks.set(Vec::new());
