            h3 { "Bed Board" }
            p { class: "muted", "Live polling every 8 seconds with state chips and an event timeline." }
            div { class: "grid-2",
                section { class: "subpanel",
                    h4 { "Beds" }
                    div { class: "cards",
                        for bed in beds() {
                            article { class: "card bed-card",
