                        p { class: "muted", "Dish #{c.dish_id} / threshold {c.success_threshold} / deadline {c.success_deadline_at}" }
                        p { class: "muted", "{c.status} / participants {c.participants} / qualifying orders {c.qualifying_orders}" }
                    }
                }
            }
        }
    }
}
